import React, { useState } from 'react';

const AnniversaryLot = () => {
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const form = new FormData(e.target);
    const data = {
      data: {
        name: form.get('name'),
        email: form.get('email'),
        instagram: form.get('instagram'),
        phone: form.get('phone'),
      },
    };

    try {
      await fetch('https://sheetdb.io/api/v1/ya1lgmr4wqlz6', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });

      setSubmitted(true);
      window.location.href = 'https://buy.stripe.com/test_8x2cN77Sa46j6e9bB20gw00';

    } catch (error) {
      alert("Error submitting form. Please try again.");
    }
  };

  if (submitted) {
    return (
      <div className="p-8 text-center">
        <h1 className="text-2xl font-bold text-green-600">Thank you!</h1>
        <p className="mt-4">Your details were saved successfully.</p>
      </div>
    );
  }

  return (
    <>
      {/* Top Banner */}
      <section className="bg-cafe-texture bg-cover bg-center py-12 text-center text-white">
        <div className="bg-black bg-opacity-60 max-w-3xl mx-auto p-6 rounded-xl">
          <h1 className="text-4xl font-extrabold mb-2">🎉 Anniversary Lot</h1>
          <p className="text-lg">Win a Mercedes Benz A180 — the draw happens after 799 entries!</p>
        </div>
      </section>

      {/* Form Card */}
      <section className="px-4 py-10 max-w-xl mx-auto">
        <div className="bg-white bg-opacity-80 backdrop-blur rounded-xl shadow-md p-6 sm:p-8">
          <h2 className="text-2xl font-bold text-textbrown mb-6 text-center">Enter Your Details</h2>
          <form onSubmit={handleSubmit} className="grid gap-4">
            <div>
              <label className="block mb-1 font-semibold">Full Name</label>
              <input name="name" type="text" className="w-full p-2 border rounded" required />
            </div>
            <div>
              <label className="block mb-1 font-semibold">Email</label>
              <input name="email" type="email" className="w-full p-2 border rounded" required />
            </div>
            <div>
              <label className="block mb-1 font-semibold">Instagram</label>
              <input name="instagram" type="text" className="w-full p-2 border rounded" />
            </div>
            <div>
              <label className="block mb-1 font-semibold">Phone Number</label>
              <input name="phone" type="tel" className="w-full p-2 border rounded" required />
            </div>
            <button
              type="submit"
              className="mt-4 bg-cafebrown text-white px-6 py-2 rounded hover:bg-opacity-90 transition"
            >
              Save & Continue
            </button>
          </form>
        </div>
      </section>

      {/* Info Section */}
      <section className="max-w-3xl mx-auto px-6 pb-12 text-textbrown">
        <div className="bg-white p-6 rounded-xl shadow-md">
          <h3 className="text-xl font-bold mb-4">📌 How It Works</h3>
          <ul className="list-disc list-inside space-y-2 text-sm sm:text-base">
            <li>Fill in your details and continue to payment</li>
            <li>Follow @ila.cafe on Instagram</li>
            <li>Post your food experience & tag us</li>
            <li>The winner will be drawn once <strong>799 entries</strong> are received</li>
            <li>We’ll announce the winner on Instagram</li>
          </ul>
        </div>
      </section>
    </>
  );
};

export default AnniversaryLot;
